import android.content.Context;
import android.content.SharedPreferences;
import android.hardware.fingerprint.FingerprintManager;
import android.os.CancellationSignal;
import android.support.v4.hardware.fingerprint.FingerprintManagerCompat;
import android.widget.Toast;

public class BiometricAuth {
    private static final String PREF_AUTHENTICATED = "authenticated";

    public static void authenticate(Context context) {
        FingerprintManagerCompat fingerprintManager = FingerprintManagerCompat.from(context);
        if (!fingerprintManager.isHardwareDetected()) {
            Toast.makeText(context, "Fingerprint authentication not supported on this device.", Toast.LENGTH_SHORT).show();
            return;
        }

        SharedPreferences preferences = context.getSharedPreferences("biometric_auth", Context.MODE_PRIVATE);
        boolean authenticated = preferences.getBoolean(PREF_AUTHENTICATED, false);

        if (authenticated) {
            // Skip login screen and proceed to main activity
            Intent intent = new Intent(context, MainActivity.class);
            context.startActivity(intent);
        } else {
            // Show fingerprint authentication prompt
            FingerprintManagerCompat.CryptoObject cryptoObject = null;
            CancellationSignal cancellationSignal = new CancellationSignal();
            BiometricPrompt biometricPrompt = new BiometricPrompt(context, new BiometricPrompt.AuthenticationCallback() {
                @Override
                public void onAuthenticationError(int errorCode, CharSequence errString) {
                    super.onAuthenticationError(errorCode, errString);
                    Toast.makeText(context, "Fingerprint authentication failed.", Toast.LENGTH_SHORT).show();
                }

                @Override
                public void onAuthenticationSucceeded(BiometricPrompt.AuthenticationResult result) {
                    super.onAuthenticationSucceeded(result);
                    // Save authentication status in SharedPreferences
                    preferences.edit().putBoolean(PREF_AUTHENTICATED, true).apply();
                    // Skip login screen and proceed to main activity
                    Intent intent = new Intent(context, MainActivity.class);
                    context.startActivity(intent);
                }
            });
            biometricPrompt.authenticate(cryptoObject, cancellationSignal);
        }
    }
}